export function structuralToolsEqual(
	a: readonly ToolDefinition[] | undefined,
	b: readonly ToolDefinition[] | undefined,
): boolean {
	const aa = a ?? [];
	const bb = b ?? [];
	if (aa.length !== bb.length) {
		return false;
	}
	const byName = new Map<string, ToolDefinition>();
	for (const t of aa) {
		byName.set(t.name, t);
	}
	for (const t of bb) {
		const prev = byName.get(t.name);
		if (!prev) {
